import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class App extends StatefulWidget {
  @override
  _AppState createState() => _AppState();
}

class _AppState extends State<App> {
  final storage = FlutterSecureStorage();

  Future<void> uploadImage(File image) async {
    final url = 'https://s3.amazonaws.com/your-bucket-name';
    final headers = {'Content-Type': 'image/jpeg'};
    final body = await http.MultipartFile.fromPath('file', image.path);
    final response = await http.post(Uri.parse(url), headers: headers, body: body);
    if (response.statusCode == 200) {
      print('Image uploaded successfully');
    } else {
      print('Error uploading image: ${response.body}');
    }
  }

  Future<void> analyzeImage(File image) async {
    final url = 'https://vision.googleapis.com/v1/images:annotate';
    final headers = {'Content-Type': 'application/json'};
    final body = jsonEncode({
      'requests': [
        {
          'image': {
            'source': {
              'gcsImageUri': 'gs://your-bucket-name/path/to/image.jpg',
            },
          },
          'features': [
            {
              'type': 'LABEL_DETECTION',
              'maxResults': 10,
            },
          ],
        },
      ],
    });
    final response = await http.post(Uri.parse(url), headers: headers, body: body);
    if (response.statusCode == 200) {
      print('Image analyzed successfully');
    } else {
      print('Error analyzing image: ${response.body}');
    }
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(
          title: Text('AWS S3 and Google Cloud Vision API Demo'),
        ),
        body: Center(
          child: ElevatedButton(
            onPressed: () async {
              final image = await ImagePicker().getImage(source: ImageSource.gallery);
              if (image != null) {
                await uploadImage(File(image.path));
                await analyzeImage(File(image.path));
              }
            },
            child: Text('Upload and Analyze Image'),
          ),
        ),
      ),
    );
  }
}